const config = {"environment":{"name":"production"},"telegram":{"source_groups":{"enabled":false,"groups":[]},"expert_group":{"chat_id":-1003811712654,"title":"Telegram Support Experts"},"parse_mode":"HTML"},"rabbitmq":{"exchanges":{"support":"tg.support","dead_letter":"tg.dlx"},"queues":{"delay":"tg.delay","escalation":"tg.escalation"},"routing_keys":{"delay":"delay","escalation":"tg.escalation"},"delay_ttl_ms":60000},"openai":{"default_model":"gpt-5-mini"},"languages":{"supported":["ru","uk","pl","en","other"],"default_fallback":"other"}};

const errors = [];
const read = (path) => path.split('.').reduce((current, key) => current?.[key], config);

const requireString = (path) => {
  const value = read(path);
  if (typeof value !== 'string' || value.trim() === '') errors.push(`${path} must be a non-empty string`);
};

const requireInteger = (path) => {
  const value = read(path);
  if (!Number.isInteger(value)) errors.push(`${path} must be an integer`);
};

const requirePositiveInteger = (path) => {
  const value = read(path);
  if (!Number.isInteger(value) || value <= 0) errors.push(`${path} must be a positive integer`);
};

[
  'environment.name',
  'telegram.parse_mode',
  'rabbitmq.exchanges.support',
  'rabbitmq.exchanges.dead_letter',
  'rabbitmq.queues.delay',
  'rabbitmq.queues.escalation',
  'rabbitmq.routing_keys.delay',
  'rabbitmq.routing_keys.escalation',
  'openai.default_model'
].forEach(requireString);

requireInteger('telegram.expert_group.chat_id');
requirePositiveInteger('rabbitmq.delay_ttl_ms');

const supportedLanguages = read('languages.supported');
if (!Array.isArray(supportedLanguages) || supportedLanguages.length === 0) {
  errors.push('languages.supported must be a non-empty array');
} else if (supportedLanguages.some((language) => typeof language !== 'string' || language.trim() === '')) {
  errors.push('languages.supported must contain only non-empty strings');
}

const fallbackLanguage = read('languages.default_fallback');
if (typeof fallbackLanguage !== 'string' || fallbackLanguage.trim() === '') {
  errors.push('languages.default_fallback must be a non-empty string');
} else if (Array.isArray(supportedLanguages) && !supportedLanguages.includes(fallbackLanguage)) {
  errors.push('languages.default_fallback must be included in languages.supported');
}

if (errors.length) {
  throw new Error(`Production config validation failed: ${errors.join('; ')}`);
}

return [{
  ...$json,
  config
}];

const ai = $json;

const state = $('Load Runtime State').item.json;

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const messages = Array.isArray(state.runtime_state?.messages)
  ? state.runtime_state.messages
  : [];

const questions = (ai.questions || [])
  .map((q, i) => `${i + 1}. ${escapeHtml(q)}`)
  .join('\n') || 'Питання відсутні.';

const conversation = messages.length
  ? messages
    .map((message, i) => `${i + 1}. ${escapeHtml(message?.text || '') || 'Порожнє повідомлення.'}`)
    .join('\n\n')
  : 'Повідомлення відсутні.';

const conversationBlock = `<blockquote expandable><b>Повний текст звернення:</b>\n\n${conversation}</blockquote>`;

const firstMessageId =
  messages[0]?.message_id;

const internalChatId =
  String(state.chat_id).replace('-100', '');

const messageLink =
  `https://t.me/c/${internalChatId}/${firstMessageId}`;

const messageCount =
  messages.length;

const expertMessage = `🔔 Звернення #${state.id}

<b>Група:</b>
${escapeHtml(state.chat_title || 'Невідома група')}

<b>Користувач:</b>
${escapeHtml(state.user_name || 'Невідомий користувач')}

<b>Telegram ID:</b>
${state.user_id}

<b>Короткий опис:</b>
${escapeHtml(ai.topic)}

<b>Питання:</b>
${questions}

${conversationBlock}

<b>Посилання:</b>
<a href="${escapeHtml(messageLink)}">Відкрити повідомлення</a>

<b>Повідомлень у зверненні:</b>
${messageCount}`;

return [{
  ...state,
  ...ai,
  expert_message: expertMessage
}];

