const state = $('Load Runtime State').item.json;

const ai = $json.output;

const runtime = state.runtime_state || {};

runtime.analysis = {
  language: ai.language,
  topic: ai.topic,
  questions: ai.questions || [],
  needs_escalation: ai.needs_escalation,
  analyzed_at: new Date().toISOString()
};

return [{
  ...state,
  runtime_state: runtime,

  language: ai.language,
  topic: ai.topic,
  questions: ai.questions || [],
  needs_escalation: ai.needs_escalation
}];

const lang = $json.language;
const fallbackLang = $('Load Production Config').item.json.config.languages.default_fallback;
const topic = $json.topic || 'Вашого звернення';

const messages = {
uk: `Дякуємо за звернення.

Ваш запит щодо <b>${topic}</b> передано команді підтримки.
Наші консультанти вивчать деталі та нададуть відповідь прямо тут, у цьому чаті.

Це автоматичне повідомлення. Наш консультант приєднається до діалогу якомога швидше.`,

ru: `Спасибо за обращение.

Ваш запрос по теме <b>${topic}</b> передан в службу поддержки.
Наши консультанты изучат детали и ответят прямо здесь, в этом чате.

Это автоматическое сообщение. Наш консультант присоединится к разговору как можно скорее.`,

pl: `Dziękujemy za kontakt.

Twoje zgłoszenie dotyczące <b>${topic}</b> zostało przekazane zespołowi wsparcia.
Nasi konsultanci zapoznają się ze szczegółami i udzielą odpowiedzi bezpośrednio tutaj, na tym czacie.

To jest wiadomość automatyczna. Nasz konsultant dołączy do rozmowy tak szybko, jak to możliwe.`,

en: `Thank you for contacting us.

Your inquiry regarding <b>${topic}</b> has been forwarded to our support team.
Our representatives will review the details and respond right here in this chat.

This is an automated message. One of our specialists will join the conversation as soon as possible.`,

other: `Thank you for contacting us.

Your inquiry regarding <b>${topic}</b> has been forwarded to our support team.
Our representatives will review the details and respond right here in this chat.

This is an automated message. One of our specialists will join the conversation as soon as possible.`
};

return [{
...$json,
user_message: messages[lang] || messages[fallbackLang]
}];

